class Solution(object):
    def rotateElements(self, nums, k):
        pos_indices = [i for i, x in enumerate(nums) if x >= 0]
        pos_vals = [nums[i] for i in pos_indices]
        m = len(pos_vals)
        if m == 0:
            return list(nums)
        k = k % m
        rotated = pos_vals[k:] + pos_vals[:k]
        result = list(nums)
        for idx, val in zip(pos_indices, rotated):
            result[idx] = val
        return result
